import React, { Fragment, createContext, useReducer } from "react";
import DashboardCard from "./DashboardCard";
import Customize from "./Customize";
import { dashboardState, dashboardReducer } from "./DashboardContext";
import TodaySell from "./TodaySell";
import AllOrders from "../../admin/orders/AllOrders";
import { orderState, orderReducer, OrderContext } from "../../admin/orders";

export const DashboardContext = createContext();

const SuperAdminDashboardComponent = () => {
  const [orderData, orderDispatch] = useReducer(orderReducer, orderState);
  return (
    <Fragment>
      <DashboardCard />
      <Customize />
      <TodaySell />
      <OrderContext.Provider value={{ data: orderData, dispatch: orderDispatch }}>
        <AllOrders />
      </OrderContext.Provider>
    </Fragment>
  );
};

const SuperAdminDashboard = (props) => {
  const [data, dispatch] = useReducer(dashboardReducer, dashboardState);
  return (
    <Fragment>
      <DashboardContext.Provider value={{ data, dispatch }}>
        <SuperAdminDashboardComponent />
      </DashboardContext.Provider>
    </Fragment>
  );
};

export default SuperAdminDashboard;
